package cl.duoc.vetcontrol.atencion.controller;
import cl.duoc.vetcontrol.atencion.dto.AtencionRequest; import cl.duoc.vetcontrol.atencion.model.Atencion; import cl.duoc.vetcontrol.atencion.service.AtencionService; import jakarta.validation.Valid; import org.springframework.http.*; import org.springframework.web.bind.annotation.*; import java.util.List;
@RestController @RequestMapping("/api/v1/atenciones")
public class AtencionController { private final AtencionService service; public AtencionController(AtencionService service){this.service=service;} @GetMapping public ResponseEntity<List<Atencion>> all(){return ResponseEntity.ok(service.findAll());} @GetMapping("/{id}") public ResponseEntity<Atencion> one(@PathVariable Long id){return ResponseEntity.ok(service.findById(id));} @GetMapping("/mascotas/{mascotaId}") public ResponseEntity<List<Atencion>> byMascota(@PathVariable Long mascotaId){return ResponseEntity.ok(service.byMascota(mascotaId));} @PostMapping public ResponseEntity<Atencion> create(@Valid @RequestBody AtencionRequest r){return ResponseEntity.status(HttpStatus.CREATED).body(service.create(r));}}
